package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class ControleRegulBelastbaar extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            controleerRegulNegatiefBelastbaar(mainContext, opdracht);
        }
        return CONTINUE_PROCESSING;
    }

    private void controleerRegulNegatiefBelastbaar(RekenContext mainContext, Opdracht opdracht) {
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        MoneyMap<BelastbaarKey> belastbaarMap = new HashMoneyMap<>();
        for (LoonElement element : loonElementen) {
            LnedefRegBv regime = element.getRegimeBv();
            BelastbaarKey key = new BelastbaarKey(regime);
            Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
            belastbaarMap.addToMoney(key, belastbaar);
        }
        Money belastbaar14Tao = belastbaarMap.getMoney(new BelastbaarKey(LnedefRegBv.VD_BV_14_TAO));
        if (belastbaar14Tao.signum() < 0) {
            regulManager.doRegulException(opdracht, Regulkode.NEGATIEVE_BB_14_TAO);
        }
        boolean heeftArbeidsOngeval = false;
        for (LoonElement element : loonElementen) {
            if (LoonCodeTools.isArbeidsOngeval(element.getAardKodeExtensie())) {
                heeftArbeidsOngeval = true;
                break;
            }
        }
        if (heeftArbeidsOngeval) {
            Money belastbaarGewoon = belastbaarMap.getMoney(new BelastbaarKey(LnedefRegBv.VD_BV_10_BZ___GB));
            if (belastbaarGewoon.signum() < 0) {
                regulManager.doRegulException(opdracht, Regulkode.BB_10_BZ___GB_NEGATIEF_CASUS_AO);
            }
        }

    }

}
